INSERT INTO bluenote_note.note (
    note_id, author_id, note_type, note_status, visibility, current_version, latest_version,
    cover_file_id, comment_enabled, published_at, last_edited_at, offline_reason,
    deleted_at, created_at, updated_at, deleted
) VALUES (
    #{noteId}, #{authorId}, #{noteType}, #{noteStatus}, #{visibility}, #{currentVersion}, #{latestVersion},
    #{coverFileId}, #{commentEnabled}, #{publishedAt}, #{lastEditedAt}, #{offlineReason},
    #{deletedAt}, #{createdAt}, #{updatedAt}, #{deleted}
)

mapper.select:
SELECT 
FROM bluenote_note.note
WHERE author_id = #{authorId}
  AND note_status = 'PUBLISHED'
  AND visibility = 'PUBLIC'
  AND deleted = 0

  AND (
    published_at < #{cursorPublishedAt}
    OR (published_at = #{cursorPublishedAt} AND note_id < #{cursorNoteId})
  )

ORDER BY published_at DESC, note_id DESC
LIMIT #{size}

SELECT FROM bluenote_note.note WHERE note_status = 'PUBLISHED' AND visibility = 'PUBLIC' AND deleted = 0
AND ( published_at < #{cursorPublishedAt} OR (published_at = #{cursorPublishedAt} AND note_id < #{cursorNoteId}) )
ORDER BY published_at DESC, note_id DESC LIMIT #{size}

SELECT 
FROM bluenote_note.note
WHERE author_id = #{authorId}
  AND deleted = 0

  AND note_status = #{status}


  AND (
    COALESCE(published_at, updated_at) < #{cursorSortAt}
    OR (COALESCE(published_at, updated_at) = #{cursorSortAt} AND note_id < #{cursorNoteId})
  )

ORDER BY COALESCE(published_at, updated_at) DESC, note_id DESC
LIMIT #{size}

SELECT note.note_id, note.author_id, note.note_type, note.note_status, note.visibility, note.current_version, note.latest_version, note.cover_file_id, note.comment_enabled, note.published_at, note.last_edited_at, note.offline_reason, note.deleted_at, note.created_at, note.updated_at, note.deleted, collection_item.collected_at AS interaction_at FROM bluenote_note.note_collection collection_item INNER JOIN bluenote_note.note note ON note.note_id = collection_item.note_id WHERE collection_item.user_id = #{userId} AND collection_item.collection_status = 'ACTIVE' AND note.deleted = 0 AND ( (note.note_status = 'PUBLISHED' AND note.visibility = 'PUBLIC') OR (note.author_id = #{userId} AND note.note_status IN ('PUBLISHED', 'PRIVATE')) )
AND ( collection_item.collected_at < #{cursorInteractionAt} OR (collection_item.collected_at = #{cursorInteractionAt} AND note.note_id < #{cursorNoteId}) )
ORDER BY collection_item.collected_at DESC, note.note_id DESC LIMIT #{size}

SELECT note.note_id, note.author_id, note.note_type, note.note_status, note.visibility, note.current_version, note.latest_version, note.cover_file_id, note.comment_enabled, note.published_at, note.last_edited_at, note.offline_reason, note.deleted_at, note.created_at, note.updated_at, note.deleted, note_like.liked_at AS interaction_at FROM bluenote_note.note_like note_like INNER JOIN bluenote_note.note note ON note.note_id = note_like.note_id WHERE note_like.user_id = #{userId} AND note_like.like_status = 'ACTIVE' AND note.deleted = 0 AND ( (note.note_status = 'PUBLISHED' AND note.visibility = 'PUBLIC') OR (note.author_id = #{userId} AND note.note_status IN ('PUBLISHED', 'PRIVATE')) )
AND ( note_like.liked_at < #{cursorInteractionAt} OR (note_like.liked_at = #{cursorInteractionAt} AND note.note_id < #{cursorNoteId}) )
ORDER BY note_like.liked_at DESC, note.note_id DESC LIMIT #{size}

SELECT note_id, author_id, note_type, note_status, visibility, current_version, latest_version, cover_file_id, comment_enabled, published_at, last_edited_at, offline_reason, deleted_at, created_at, updated_at, deleted FROM ( SELECT , ROW_NUMBER() OVER (PARTITION BY author_id ORDER BY published_at DESC, note_id DESC) AS row_no FROM bluenote_note.note WHERE deleted = 0 AND note_status = 'PUBLISHED' AND visibility = 'PUBLIC' AND author_id IN
#{authorId}
AND published_at >= #{publishedAfter}
) recent_notes WHERE row_no <= #{size} ORDER BY published_at DESC, note_id DESC
